def gen(rng, size):
    alphabet = 'abcdefghijklmnopqrstuvwxyz'
    def rand_word():
        length = rng.randint(1, 12)
        idxs = rng.sample(range(26), length)
        return ''.join(alphabet[i] for i in idxs)
    n = max(1, min(size, 3000))
    startWords = [rand_word() for _ in range(n)]
    targetWords = [rand_word() for _ in range(n)]
    return [startWords, targetWords]

