class Solution:
    def wordCount(self, startWords, targetWords):
        def mask_of(w):
            m = 0
            for c in w:
                m |= 1 << (ord(c) - 97)
            return m
        start_masks = [mask_of(w) for w in startWords]
        count = 0
        for t in targetWords:
            tmask = mask_of(t)
            tlen = len(t)
            found = False
            for smask in start_masks:
                if bin(smask).count('1') != tlen - 1:
                    continue
                if (smask & tmask) == smask:
                    found = True
                    break
            if found:
                count += 1
        return count

