class Solution:
    def wordCount(self, startWords, targetWords):
        start_set = set()
        for w in startWords:
            mask = 0
            for c in w:
                mask |= 1 << (ord(c) - 97)
            start_set.add(mask)
        count = 0
        for w in targetWords:
            mask = 0
            for c in w:
                mask |= 1 << (ord(c) - 97)
            found = False
            for c in w:
                bit = 1 << (ord(c) - 97)
                reduced = mask ^ bit
                if reduced in start_set:
                    found = True
                    break
            if found:
                count += 1
        return count

