var wordCount = function(startWords, targetWords) {
    const maskOf = (w) => {
        let m = 0;
        for (const c of w) m |= 1 << (c.charCodeAt(0) - 97);
        return m;
    };
    const startSet = new Set();
    for (const w of startWords) startSet.add(maskOf(w));
    let count = 0;
    for (const w of targetWords) {
        const m = maskOf(w);
        let found = false;
        for (const c of w) {
            const bit = 1 << (c.charCodeAt(0) - 97);
            const reduced = m ^ bit;
            if (startSet.has(reduced)) {
                found = true;
                break;
            }
        }
        if (found) count++;
    }
    return count;
};
